javascript:(()=>{function injectStyles(){document.head.insertAdjacentHTML("beforeend","<style>.modal-window {position: fixed;display: flex;justify-content: center;align-items: center;background-color: rgba(0, 0, 0, 0.6);backdrop-filter: blur(4px);top: 0;right: 0;bottom: 0;left: 0;z-index: 999;opacity: 0;pointer-events: none;font-family: Arial, Helvetica, sans-serif !important;}.modal-window:target {opacity: 1;pointer-events: auto;}.modal-window > div {width: 480px;position: absolute;padding: 2em 2.5em;background: #ffffff;color: #333333;border-radius: 10px;box-shadow: 0 8px 30px rgba(0, 0, 0, 0.3);}.modal-close {color: #666;font-size: 14px;line-height: 32px;position: absolute;right: 12px;text-align: center;top: 12px;width: 64px;text-decoration: none;border: 1px solid #ccc;border-radius: 6px;transition: background 0.2s, border-color 0.2s;}.modal-close:hover {background: #f0f0f0;border-color: #999;}.modal-window > div > ul > li,.modal-window #MSDLinfo ul > li {margin: 5px 0 !important;padding: 0 !important;line-height: 1.5 !important;}.MSDLthumbnail {width: 350px;vertical-align: middle;margin-bottom: 4px;border-radius: 4px;}div#MSDLinfo {max-height: 70vh;min-height: 5vh;overflow-y: auto;}.MSDLtitle-input {width: 100%;box-sizing: border-box;padding: 6px 8px;margin-top: 4px;border: 1px solid #ccc;border-radius: 4px;font-family: Arial, Helvetica, sans-serif !important;font-size: 14px;background-color: #fff;}.MSDLtitle-input:focus {outline: none;border-color: #666;}</style>")}function buildModal(e,t){let i=e.d.Presentation;if(injectStyles(),document.contains(document.getElementById("open-modal"))&&document.getElementById("open-modal").remove(),"OnDemand"!==i.PlayStatus){document.body.insertAdjacentHTML("beforeend",'<div id="open-modal" class="modal-window"><div><a href="#" title="Close" class="modal-close">Close</a><p style="font-size: 16px; line-height: 1.5;">Lecture is currently not available on-demand and therefore cannot be downloaded.<br>Try again later.</p></div></div>');return}document.body.insertAdjacentHTML("beforeend",'<div id="open-modal" class="modal-window"><div><div style="font-size: 18px;line-height: 45px;position: absolute;left: 20px;top: 8px;">MediasiteDownloader (<a href="https://github.com/KLVN/MediasiteDownloader" target="_blank" style="color: #0066cc;">GitHub</a>)</div><a href="#" title="Close" class="modal-close">Close</a><div id="MSDLinfo"><ul style="list-style: outside; !important"><li>Copy the title:<br><input type="text" onClick="this.select();" value="'+document.title.replace(/[\\/:*?"<>|]/g,"-")+'" class="MSDLtitle-input"></li><li>Right-click on the thumbnail(s) and choose "Save <span style="font-weight: bold;">link</span> as..."</li><div id="MSDLvideos"></div><li>Paste in to rename file correctly and save it</li><li>Click <a href="https://klvn.github.io/MediasiteDownloader/" target="_blank">here</a> for more detailed instructions</li></ul></div></div></div>');let o=window.location.origin,a=document.getElementById("MSDLvideos"),n="";i.Streams.flatMap(e=>e.VideoUrls.filter(e=>"video/mp4"===e.MimeType).map(t=>({thumbnail:o+e.ThumbnailUrl,videoUrl:t.Location}))).forEach(({thumbnail:e,videoUrl:t})=>{n+="<li><a href='"+t+"' target='_blank'><img class='MSDLthumbnail' src='"+e+"' alt='Video stream thumbnail'></a></li>"}),null!=i.VodcastUrl&&(n+="<li>Vodcast:<br><a href='"+i.VodcastUrl+"' target='_blank'><img class='MSDLthumbnail' src='"+o+i.ThumbnailUrl+"' alt='Vodcast thumbnail'></a></li>"),n?a.innerHTML=n:document.getElementById("MSDLinfo").innerHTML="<li>Sorry, no video(s) available.</li>",t(),location.href="#open-modal"}function handleOldMediasite(){fetch(window.location.origin+document.getElementById("ServicePath").innerHTML+"/GetPlayerOptions",{method:"POST",headers:{"Content-Type":"application/json; charset=utf-8"},body:JSON.stringify({getPlayerOptionsRequest:{ResourceId:document.getElementById("ResourceId").innerHTML,QueryString:"",UseScreenReader:"false",UrlReferrer:""}})}).then(e=>e.json()).then(e=>{console.log(e),buildModal(e,()=>Mediasite.Player.API.pause())})}function handleNewMediasite(){fetch(window.location.origin+SiteData.PlayerService+"/GetPlayerOptions",{method:"POST",headers:{"Content-Type":"application/json; charset=utf-8"},body:JSON.stringify({getPlayerOptionsRequest:{ResourceId:SiteData.PresentationId,QueryString:"",UseScreenReader:"false",UrlReferrer:""}})}).then(e=>e.json()).then(e=>{console.log(e),buildModal(e,()=>MediasitePlayer.pause())})}document.getElementById("player-iframe")&&(alert('MediasiteDownloader: A Mediasite Channel was detected. After you click "OK" you will be redirected to the video. Click Play and then again on the MediasiteDownloader bookmark.\nNote: Your browser may block the redirect. Make sure to allow pop-ups for this website.'),window.open(document.getElementById("player-iframe").src)),"object"!=typeof MediasitePlayer?handleOldMediasite():handleNewMediasite();})()